import React, { useState, useRef } from 'react';

function RadioPlayer() {
  // State to track if the stream is playing
  const [isPlaying, setIsPlaying] = useState(false);

  // Ref to hold reference to the audio element
  const audioRef = useRef(null);

  // Function to handle play and pause
  const toggleStream = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  return (
    <div>
      <button onClick={toggleStream}>
        {isPlaying ? "Stop Stream" : "Play Stream"}
      </button>
      <audio ref={audioRef} src="http://172.232.62.146:8000/radio.mp3" preload="none"></audio>
    </div>
  );
}

export default RadioPlayer;
